import{_ as e,o,c as i,a2 as r}from"./chunks/framework.DCVnL8g5.js";const m=JSON.parse('{"title":"Resolución de Conflictos y Herramientas Avanzadas","description":"","frontmatter":{},"headers":[],"relativePath":"herramientas/git/04-conflictos-y-herramientas-avanzadas.md","filePath":"herramientas/git/04-conflictos-y-herramientas-avanzadas.md","lastUpdated":1782521464000}'),t={name:"herramientas/git/04-conflictos-y-herramientas-avanzadas.md"};function s(l,a,c,n,d,u){return o(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="resolucion-de-conflictos-y-herramientas-avanzadas" tabindex="-1">Resolución de Conflictos y Herramientas Avanzadas <a class="header-anchor" href="#resolucion-de-conflictos-y-herramientas-avanzadas" aria-label="Permalink to &quot;Resolución de Conflictos y Herramientas Avanzadas&quot;">​</a></h1><hr><h2 id="resolucion-de-conflictos-en-git" tabindex="-1">Resolución de conflictos en Git <a class="header-anchor" href="#resolucion-de-conflictos-en-git" aria-label="Permalink to &quot;Resolución de conflictos en Git&quot;">​</a></h2><p>Los conflictos pueden ocurrir cuando dos ramas intentan modificar la misma parte de un archivo. Aprende cómo resolverlos:</p><h3 id="detectar-conflictos" tabindex="-1">Detectar Conflictos <a class="header-anchor" href="#detectar-conflictos" aria-label="Permalink to &quot;Detectar Conflictos&quot;">​</a></h3><ul><li>Al fusionar o reorganizar, Git marcará las áreas conflictivas en los archivos.</li></ul><h3 id="resolucion-manual" tabindex="-1">Resolución Manual <a class="header-anchor" href="#resolucion-manual" aria-label="Permalink to &quot;Resolución Manual&quot;">​</a></h3><ul><li>Abre los archivos conflictivos en un editor de código y modifica manualmente las secciones en conflicto.</li><li>Elimina las marcas de conflicto <code>&lt;&lt;&lt;&lt;&lt;&lt;&lt;</code>, <code>=======</code>, y <code>&gt;&gt;&gt;&gt;&gt;&gt;&gt;</code> una vez resuelto el conflicto.</li><li>Realiza un <code>git add</code> y <code>git commit</code> para confirmar la resolución.</li></ul><h3 id="herramientas-de-resolucion" tabindex="-1">Herramientas de Resolución <a class="header-anchor" href="#herramientas-de-resolucion" aria-label="Permalink to &quot;Herramientas de Resolución&quot;">​</a></h3><ul><li>Herramientas como <code>git mergetool</code> proporcionan una interfaz gráfica para ayudar en la resolución.</li></ul><p><strong>Zona Clave</strong>: Comprender cómo detectar, resolver y confirmar conflictos en Git.</p><hr><h2 id="uso-de-herramientas-graficas-y-gui-para-git" tabindex="-1">Uso de herramientas gráficas y GUI para Git <a class="header-anchor" href="#uso-de-herramientas-graficas-y-gui-para-git" aria-label="Permalink to &quot;Uso de herramientas gráficas y GUI para Git&quot;">​</a></h2><p>Si prefieres una interfaz gráfica en lugar de la línea de comandos, existen herramientas como Sourcetree, GitKraken y GitHub Desktop para gestionar proyectos Git.</p><h3 id="sourcetree" tabindex="-1">Sourcetree <a class="header-anchor" href="#sourcetree" aria-label="Permalink to &quot;Sourcetree&quot;">​</a></h3><ul><li>Ofrece una interfaz de usuario gráfica para ver el historial, cambios y conflictos.</li><li>Permite ejecutar comandos Git directamente.</li></ul><h3 id="gitkraken" tabindex="-1">GitKraken <a class="header-anchor" href="#gitkraken" aria-label="Permalink to &quot;GitKraken&quot;">​</a></h3><ul><li>Proporciona una potente interfaz de usuario y herramientas de colaboración.</li><li>Facilita la resolución de conflictos y la administración de ramas.</li></ul><h3 id="github-desktop" tabindex="-1">GitHub Desktop <a class="header-anchor" href="#github-desktop" aria-label="Permalink to &quot;GitHub Desktop&quot;">​</a></h3><ul><li>Integrado con GitHub, es una excelente opción para colaboradores de proyectos en GitHub.</li></ul><p><strong>Zona Clave</strong>: Aprender a utilizar herramientas gráficas para trabajar con Git y facilitar la gestión de proyectos.</p><hr><h2 id="git-stash-ocultar-y-recuperar-cambios-temporales" tabindex="-1">Git stash: ocultar y recuperar cambios temporales <a class="header-anchor" href="#git-stash-ocultar-y-recuperar-cambios-temporales" aria-label="Permalink to &quot;Git stash: ocultar y recuperar cambios temporales&quot;">​</a></h2><p>A veces, necesitas guardar temporalmente los cambios que estás realizando para cambiar de rama o resolver conflictos. El comando <code>git stash</code> es útil para esto.</p><h3 id="comandos-clave-de-git-stash" tabindex="-1">Comandos Clave de Git Stash <a class="header-anchor" href="#comandos-clave-de-git-stash" aria-label="Permalink to &quot;Comandos Clave de Git Stash&quot;">​</a></h3><ul><li><strong><code>git stash save &quot;Mensaje&quot;</code></strong>: Guarda los cambios actuales en un almacén temporal (stash) con un mensaje descriptivo.</li><li><strong><code>git stash list</code></strong>: Muestra una lista de todos los cambios guardados en el stash.</li><li><strong><code>git stash apply</code></strong>: Aplica el último stash a la rama actual.</li><li><strong><code>git stash pop</code></strong>: Aplica el último stash y lo elimina de la lista.</li></ul><p><strong>Zona Clave</strong>: Comprender cómo usar <code>git stash</code> para gestionar cambios temporales en Git.</p><hr><h2 id="bisect-depuracion-avanzada-para-encontrar-problemas-especificos" tabindex="-1">Bisect: depuración avanzada para encontrar problemas específicos <a class="header-anchor" href="#bisect-depuracion-avanzada-para-encontrar-problemas-especificos" aria-label="Permalink to &quot;Bisect: depuración avanzada para encontrar problemas específicos&quot;">​</a></h2><p>El comando <code>git bisect</code> es una herramienta útil para buscar rápidamente el commit que introdujo un problema.</p><h3 id="pasos-para-usar-git-bisect" tabindex="-1">Pasos para Usar <code>git bisect</code> <a class="header-anchor" href="#pasos-para-usar-git-bisect" aria-label="Permalink to &quot;Pasos para Usar `git bisect`&quot;">​</a></h3><ol><li>Ejecuta <code>git bisect start</code> para iniciar la búsqueda binaria.</li><li>Etiqueta un commit como bueno y otro como malo.</li><li>Git seleccionará automáticamente un commit intermedio.</li><li>Prueba el commit y etiquétalo como bueno o malo.</li><li>Repite el proceso hasta encontrar el commit problemático.</li></ol><p><strong>Zona Clave</strong>: Aprender a utilizar <code>git bisect</code> para identificar problemas específicos en la historia de commits.</p><hr><h2 id="trabajo-con-submodulos-y-repositorios-incrustados" tabindex="-1">Trabajo con submódulos y repositorios incrustados <a class="header-anchor" href="#trabajo-con-submodulos-y-repositorios-incrustados" aria-label="Permalink to &quot;Trabajo con submódulos y repositorios incrustados&quot;">​</a></h2><p>Git permite trabajar con submódulos, que son repositorios Git anidados dentro de otro repositorio. Esto es útil para incluir proyectos externos en tu propio proyecto.</p><h3 id="pasos-para-agregar-un-submodulo" tabindex="-1">Pasos para Agregar un Submódulo <a class="header-anchor" href="#pasos-para-agregar-un-submodulo" aria-label="Permalink to &quot;Pasos para Agregar un Submódulo&quot;">​</a></h3><ol><li>Ejecuta <code>git submodule add URL ruta</code> para agregar un submódulo.</li><li>Confirma los cambios.</li><li>Otros desarrolladores pueden clonar y actualizar submódulos utilizando <code>git submodule init</code> y <code>git submodule update</code>.</li></ol><p><strong>Zona Clave</strong>: Aprender a trabajar con submódulos y cómo gestionarlos en tu proyecto.</p><hr><h2 id="ejemplo-resolucion-de-conflictos-en-git" tabindex="-1">Ejemplo: Resolución de conflictos en Git <a class="header-anchor" href="#ejemplo-resolucion-de-conflictos-en-git" aria-label="Permalink to &quot;Ejemplo: Resolución de conflictos en Git&quot;">​</a></h2><p>Supongamos que estás fusionando cambios de una rama de función en tu rama principal y se produce un conflicto en un archivo llamado <code>app.js</code>. Sigue estos pasos para resolver el conflicto:</p><ol><li><p>Abre <code>app.js</code> en un editor de código.</p></li><li><p>Encuentra las secciones conflictivas marcadas entre <code>&lt;&lt;&lt;&lt;&lt;&lt;&lt;</code>, <code>=======</code>, y <code>&gt;&gt;&gt;&gt;&gt;&gt;&gt;</code>. Modifica el código para resolver el conflicto.</p></li><li><p>Elimina las marcas de conflicto <code>&lt;&lt;&lt;&lt;&lt;&lt;&lt;</code>, <code>=======</code>, y <code>&gt;&gt;&gt;&gt;&gt;&gt;&gt;</code> una vez que hayas resuelto el conflicto.</p></li><li><p>Ejecuta <code>git add app.js</code> para marcar el archivo como resuelto.</p></li><li><p>Realiza un commit para completar la resolución del conflicto:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Resuelto conflicto en app.js&quot;</span></span></code></pre></div></li><li><p>Continúa con el flujo de trabajo, como fusionar la rama o realizar más cambios.</p></li></ol><p><strong>Zona Clave</strong>: Resolver conflictos rápidamente y con precisión es crucial para mantener un flujo de trabajo eficiente en proyectos colaborativos.</p><hr><h2 id="rebase-interactivo-para-reordenar-y-combinar-commits" tabindex="-1">Rebase interactivo para reordenar y combinar commits <a class="header-anchor" href="#rebase-interactivo-para-reordenar-y-combinar-commits" aria-label="Permalink to &quot;Rebase interactivo para reordenar y combinar commits&quot;">​</a></h2><p>El rebase interactivo permite limpiar el historial de commits al reordenarlos, combinarlos o editarlos.</p><h3 id="usando-git-rebase-i" tabindex="-1">Usando <code>git rebase -i</code> <a class="header-anchor" href="#usando-git-rebase-i" aria-label="Permalink to &quot;Usando `git rebase -i`&quot;">​</a></h3><ol><li>Ejecuta <code>git rebase -i HEAD~n</code> donde <code>n</code> es el número de commits recientes que deseas editar.</li><li>Se abrirá una lista de commits en tu editor de texto.</li><li>Cambia las palabras clave al inicio de cada línea: <ul><li><code>pick</code>: Mantener el commit como está.</li><li><code>reword</code>: Editar el mensaje del commit.</li><li><code>squash</code>: Combinar este commit con el anterior.</li><li><code>edit</code>: Pausar en este commit para hacer cambios.</li></ul></li><li>Guarda y cierra el editor para aplicar los cambios.</li></ol><h3 id="precaucion" tabindex="-1">Precaución <a class="header-anchor" href="#precaucion" aria-label="Permalink to &quot;Precaución&quot;">​</a></h3><p>Usa rebase solo en commits que aún no se hayan compartido con otros colaboradores para evitar problemas.</p><p><strong>Zona Clave</strong>: El rebase interactivo es una herramienta poderosa para mantener un historial limpio y legible.</p><hr><h2 id="hooks-de-git-automatizacion-de-tareas" tabindex="-1">Hooks de Git: automatización de tareas <a class="header-anchor" href="#hooks-de-git-automatizacion-de-tareas" aria-label="Permalink to &quot;Hooks de Git: automatización de tareas&quot;">​</a></h2><p>Los hooks de Git permiten ejecutar scripts automáticamente en respuesta a eventos como commits, merges, o pushes.</p><h3 id="ejemplo-de-hooks" tabindex="-1">Ejemplo de Hooks <a class="header-anchor" href="#ejemplo-de-hooks" aria-label="Permalink to &quot;Ejemplo de Hooks&quot;">​</a></h3><ul><li><code>pre-commit</code>: Ejecuta tareas antes de realizar un commit, como verificar el estilo de código.</li><li><code>post-merge</code>: Ejecuta scripts después de una fusión, como instalar dependencias.</li></ul><h3 id="configurar-un-hook" tabindex="-1">Configurar un Hook <a class="header-anchor" href="#configurar-un-hook" aria-label="Permalink to &quot;Configurar un Hook&quot;">​</a></h3><ol><li><p>Navega al directorio <code>.git/hooks/</code>.</p></li><li><p>Crea o edita un archivo de script correspondiente al evento, como <code>pre-commit</code>.</p></li><li><p>Asegúrate de que el script sea ejecutable:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .git/hooks/pre-commit</span></span></code></pre></div></li></ol><p><strong>Zona Clave</strong>: Automatizar tareas comunes usando hooks mejora la productividad y reduce errores humanos.</p><hr><h2 id="reflog-recuperar-referencias-perdidas" tabindex="-1">Reflog: recuperar referencias perdidas <a class="header-anchor" href="#reflog-recuperar-referencias-perdidas" aria-label="Permalink to &quot;Reflog: recuperar referencias perdidas&quot;">​</a></h2><p>El comando <code>git reflog</code> permite ver un registro de todas las acciones realizadas en el repositorio, incluso aquellas que no están en el historial visible.</p><h3 id="usos-comunes" tabindex="-1">Usos Comunes <a class="header-anchor" href="#usos-comunes" aria-label="Permalink to &quot;Usos Comunes&quot;">​</a></h3><ul><li>Recuperar commits perdidos después de un reset o rebase.</li><li>Identificar el HEAD de un estado previo.</li></ul><h3 id="comandos-clave" tabindex="-1">Comandos Clave <a class="header-anchor" href="#comandos-clave" aria-label="Permalink to &quot;Comandos Clave&quot;">​</a></h3><ul><li><code>git reflog</code>: Muestra el registro de referencias.</li><li><code>git checkout &lt;referencia&gt;</code>: Mueve el HEAD a un estado previo basado en el reflog.</li></ul><h3 id="ejemplo-practico-de-git-reflog" tabindex="-1">Ejemplo Práctico de <code>git reflog</code> <a class="header-anchor" href="#ejemplo-practico-de-git-reflog" aria-label="Permalink to &quot;Ejemplo Práctico de `git reflog`&quot;">​</a></h3><ol><li>Ejecuta un comando que cambie el estado del repositorio, como un <code>git reset</code>.</li><li>Si pierdes cambios accidentalmente, usa <code>git reflog</code> para encontrar el SHA del commit perdido.</li><li>Restaura el estado con <code>git checkout</code> o <code>git reset</code>.</li></ol><p><strong>Zona Clave</strong>: El reflog es una herramienta indispensable para recuperar cambios aparentemente perdidos.</p>',70)])])}const h=e(t,[["render",s]]);export{m as __pageData,h as default};
